package me.tx.crazydog.camera2;

import android.media.Image;
import android.media.ImageReader;
import android.util.Log;

import java.nio.ByteBuffer;

/**
 * Callback that receives ImageReader frames, converts YUV_420_888 to NV21 and forwards
 * the byte[] to a listener.
 */
public class Camera2FrameCallback implements ImageReader.OnImageAvailableListener {
	private static final String TAG = "Camera2FrameCallback";

	public interface FrameListener {
		void onFrameResult(byte[] nv21Data, int width, int height);
	}

	private FrameListener mListener;

	public void setFrameListener(FrameListener listener) {
		this.mListener = listener;
	}

	@Override
	public void onImageAvailable(ImageReader reader) {
		Image image = null;
		try {
			image = reader.acquireLatestImage();
			if (image == null) return;

			byte[] nv21 = getNV21DataFromImage(image);
			if (nv21 != null && mListener != null) {
				mListener.onFrameResult(nv21, image.getWidth(), image.getHeight());
			}
		} catch (Exception e) {
			Log.e(TAG, "onImageAvailable error", e);
		} finally {
			if (image != null) image.close();
		}
	}

	/**
	 * Convert YUV_420_888 Image to NV21 byte[]
	 */
	public static byte[] getNV21DataFromImage(Image image) {
		if (image == null) return null;

		final int width = image.getWidth();
		final int height = image.getHeight();

		Image.Plane[] planes = image.getPlanes();
		ByteBuffer yBuffer = planes[0].getBuffer(); // Y
		ByteBuffer uBuffer = planes[1].getBuffer(); // U (Cb)
		ByteBuffer vBuffer = planes[2].getBuffer(); // V (Cr)

		int ySize = yBuffer.remaining();
		int uSize = uBuffer.remaining();
		int vSize = vBuffer.remaining();

		byte[] nv21 = new byte[ySize + uSize + vSize];

		// Copy Y
		yBuffer.get(nv21, 0, ySize);

		// NV21 requires VU interleaved
		// U and V planes may have different pixelStride/rowStride; we must handle that
		int chromaHeight = height / 2;
		int chromaWidth = width / 2;

		int offset = ySize;

		int uPixelStride = planes[1].getPixelStride();
		int uRowStride = planes[1].getRowStride();
		int vPixelStride = planes[2].getPixelStride();
		int vRowStride = planes[2].getRowStride();

		byte[] uRow = new byte[uRowStride];
		byte[] vRow = new byte[vRowStride];

		// Iterate through chroma rows
		for (int row = 0; row < chromaHeight; row++) {
			int uRowStart = row * uRowStride;
			int vRowStart = row * vRowStride;

			// Read a whole row from each plane into temporary arrays
			// Note: using get() with position adjustments
			int uPos = uRowStart;
			int vPos = vRowStart;

			// Fill temporary arrays from underlying buffers
			// Duplicate buffers to avoid changing position on original
			ByteBuffer uBuf = planes[1].getBuffer().duplicate();
			ByteBuffer vBuf = planes[2].getBuffer().duplicate();
			uBuf.position(uRowStart);
			vBuf.position(vRowStart);
			int uLen = Math.min(uRowStride, uBuf.remaining());
			int vLen = Math.min(vRowStride, vBuf.remaining());
			uBuf.get(uRow, 0, uLen);
			vBuf.get(vRow, 0, vLen);

			for (int col = 0; col < chromaWidth; col++) {
				int uIndex = col * uPixelStride;
				int vIndex = col * vPixelStride;

				// NV21 is V then U
				if (vIndex < vRow.length) nv21[offset++] = vRow[vIndex];
				else nv21[offset++] = 0;
				if (uIndex < uRow.length) nv21[offset++] = uRow[uIndex];
				else nv21[offset++] = 0;
			}
		}

		return nv21;
	}
}

package me.tx.crazydog.camera2;

import android.content.Context;
import android.hardware.camera2.CameraAccessException;
import android.hardware.camera2.CameraCaptureSession;
import android.hardware.camera2.CameraCharacteristics;
import android.hardware.camera2.CameraDevice;
import android.hardware.camera2.CameraManager;
import android.hardware.camera2.CaptureRequest;
import android.os.Handler;
import android.os.HandlerThread;
import android.util.Log;
import android.view.Surface;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.List;

/**
 * Core manager for Camera2. Handles opening/closing camera, creating capture session and preview
 * while forwarding frames via ImageReaderManager.
 */
public class CameraDeviceManager {
	private static final String TAG = "CameraDeviceManager";

	private CameraManager mCameraManager;
	private CameraDevice mCameraDevice;
	private ImageReaderManager mImageReaderManager;
	private CameraCaptureSession mCaptureSession;

	private HandlerThread mBackgroundThread;
	private Handler mBackgroundHandler;

	private CaptureRequest.Builder mPreviewRequestBuilder;
	private CaptureRequest mPreviewRequest;

	public CameraDeviceManager() {
		mImageReaderManager = new ImageReaderManager();
	}

	public void initCameraManager(Context context) {
		if (context == null) return;
		mCameraManager = (CameraManager) context.getSystemService(Context.CAMERA_SERVICE);
		startBackgroundThread();
	}

	public String[] getCameraIdList() {
		if (mCameraManager == null) return new String[0];
		try {
			return mCameraManager.getCameraIdList();
		} catch (CameraAccessException e) {
			Log.e(TAG, "getCameraIdList failed", e);
			return new String[0];
		}
	}

	public CameraCharacteristics getCameraCharacteristics(String cameraId) {
		if (mCameraManager == null) return null;
		try {
			return mCameraManager.getCameraCharacteristics(cameraId);
		} catch (CameraAccessException e) {
			Log.e(TAG, "getCameraCharacteristics failed", e);
			return null;
		}
	}

	public void openCamera(String cameraId) {
		if (mCameraManager == null) {
			Log.w(TAG, "CameraManager not initialized");
			return;
		}
		try {
			mCameraManager.openCamera(cameraId, mStateCallback, mBackgroundHandler);
		} catch (SecurityException e) {
			Log.e(TAG, "openCamera: missing permission?", e);
		} catch (CameraAccessException e) {
			Log.e(TAG, "openCamera failed", e);
		}
	}

	public void closeCamera() {
		try {
			if (mCaptureSession != null) {
				try { mCaptureSession.stopRepeating(); } catch (Exception ignored) {}
				try { mCaptureSession.abortCaptures(); } catch (Exception ignored) {}
				mCaptureSession.close();
				mCaptureSession = null;
			}
			if (mCameraDevice != null) {
				mCameraDevice.close();
				mCameraDevice = null;
			}
		} catch (Exception e) {
			Log.e(TAG, "closeCamera error", e);
		}
	}

	/**
	 * Create capture session with the ImageReader surface (used for frame callback).
	 * This will be called internally by startPreview().
	 */
	public void createCaptureSession() {
		if (mCameraDevice == null) {
			Log.w(TAG, "createCaptureSession: cameraDevice is null");
			return;
		}
		Surface surface = mImageReaderManager.getSurface();
		if (surface == null) {
			Log.w(TAG, "createCaptureSession: imageReader surface is null");
			return;
		}

		try {
			List<Surface> surfaces = new ArrayList<>();
			surfaces.add(surface);
			mCameraDevice.createCaptureSession(surfaces, mSessionCallback, mBackgroundHandler);
		} catch (CameraAccessException e) {
			Log.e(TAG, "createCaptureSession failed", e);
		}
	}

	public void startPreview() {
		if (mCameraDevice == null) {
			Log.w(TAG, "startPreview: cameraDevice is null");
			return;
		}
		createCaptureSession();
	}

	public void stopPreview() {
		if (mCaptureSession != null) {
			try {
				mCaptureSession.stopRepeating();
			} catch (Exception e) {
				Log.w(TAG, "stopPreview issue", e);
			}
		}
	}

	public void releaseCamera() {
		closeCamera();
		stopBackgroundThread();
		if (mImageReaderManager != null) {
			mImageReaderManager.releaseImageReader();
			mImageReaderManager = null;
		}
	}

	public ImageReaderManager getImageReaderManager() {
		return mImageReaderManager;
	}

	private void startBackgroundThread() {
		if (mBackgroundThread != null) return;
		mBackgroundThread = new HandlerThread("CameraBackground");
		mBackgroundThread.start();
		mBackgroundHandler = new Handler(mBackgroundThread.getLooper());
	}

	private void stopBackgroundThread() {
		if (mBackgroundThread == null) return;
		try {
			mBackgroundThread.quitSafely();
			mBackgroundThread.join();
		} catch (InterruptedException e) {
			Log.w(TAG, "stopBackgroundThread interrupted", e);
		}
		mBackgroundThread = null;
		mBackgroundHandler = null;
	}

	private final CameraDevice.StateCallback mStateCallback = new CameraDevice.StateCallback() {
		@Override
		public void onOpened(CameraDevice camera) {
			mCameraDevice = camera;
			Log.d(TAG, "camera opened");
		}

		@Override
		public void onDisconnected(CameraDevice camera) {
			Log.w(TAG, "camera disconnected");
			camera.close();
			mCameraDevice = null;
		}

		@Override
		public void onError(CameraDevice camera, int error) {
			Log.e(TAG, "camera error: " + error);
			camera.close();
			mCameraDevice = null;
		}
	};

	private final CameraCaptureSession.StateCallback mSessionCallback = new CameraCaptureSession.StateCallback() {
		@Override
		public void onConfigured(CameraCaptureSession session) {
			if (mCameraDevice == null) return;
			mCaptureSession = session;
			try {
				Surface surface = mImageReaderManager.getSurface();
				mPreviewRequestBuilder = mCameraDevice.createCaptureRequest(CameraDevice.TEMPLATE_PREVIEW);
				mPreviewRequestBuilder.addTarget(surface);
				mPreviewRequestBuilder.set(CaptureRequest.CONTROL_MODE, CaptureRequest.CONTROL_MODE_AUTO);
				mPreviewRequest = mPreviewRequestBuilder.build();
				mCaptureSession.setRepeatingRequest(mPreviewRequest, null, mBackgroundHandler);
				Log.d(TAG, "capture session configured and repeating request started");
			} catch (CameraAccessException e) {
				Log.e(TAG, "onConfigured error", e);
			}
		}

		@Override
		public void onConfigureFailed(CameraCaptureSession session) {
			Log.e(TAG, "capture session configuration failed");
		}
	};

	/**
	 * Attach an ImageReader callback and prepare ImageReader. Caller should call initImageReader first
	 * via getImageReaderManager().initImageReader(width,height) then set listener.
	 */
	public void setFrameCallback(Camera2FrameCallback.FrameListener listener) {
		if (mImageReaderManager == null) return;
		Camera2FrameCallback callback = new Camera2FrameCallback();
		callback.setFrameListener(listener);
		mImageReaderManager.setOnImageAvailableListener(callback, mBackgroundHandler);
	}
}

package me.tx.crazydog.camera2;

import android.media.ImageReader;
import android.util.Log;
import android.view.Surface;

/**
 * Manages an ImageReader configured for YUV_420_888 and forwards frames to Camera2FrameCallback.
 */
public class ImageReaderManager {
	private static final String TAG = "ImageReaderManager";

	private ImageReader mImageReader;
	private Camera2FrameCallback mFrameCallback;

	public ImageReaderManager() {
	}

	/**
	 * Initialize the ImageReader for given size. Format is YUV_420_888.
	 */
	public void initImageReader(int width, int height) {
		if (mImageReader != null) {
			releaseImageReader();
		}
		mImageReader = ImageReader.newInstance(width, height, android.graphics.ImageFormat.YUV_420_888, 2);
	}

	public Surface getSurface() {
		if (mImageReader == null) return null;
		return mImageReader.getSurface();
	}

	/**
	 * Set a Camera2FrameCallback and attach it to the ImageReader.
	 */
	public void setOnImageAvailableListener(Camera2FrameCallback callback, android.os.Handler handler) {
		if (mImageReader == null) {
			Log.w(TAG, "setOnImageAvailableListener called before initImageReader");
			return;
		}
		this.mFrameCallback = callback;
		mImageReader.setOnImageAvailableListener(mFrameCallback, handler);
	}

	/**
	 * Release the ImageReader resources
	 */
	public void releaseImageReader() {
		if (mImageReader != null) {
			try {
				mImageReader.setOnImageAvailableListener(null, null);
			} catch (Exception ignored) {
			}
			Surface s = mImageReader.getSurface();
			if (s != null) {
				try { s.release(); } catch (Exception ignored) {}
			}
			mImageReader.close();
			mImageReader = null;
		}
		mFrameCallback = null;
	}
}
